Use MAUI's `Window` lifecycle events combined with `Preferences` for lightweight persistence:

```csharp
// NotePage.xaml.cs
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();

        // Subscribe to window lifecycle events
        this.Loaded += (s, e) =>
        {
            var window = this.Window;
            window.Resumed += OnAppResumed;
            window.Stopped += OnAppBackgrounded;
        };

        // Restore any saved draft on creation
        RestoreDraft();
    }

    private void OnAppBackgrounded(object sender, EventArgs e)
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void OnAppResumed(object sender, EventArgs e)
    {
        RestoreDraft();
    }

    private void RestoreDraft()
    {
        var saved = Preferences.Get(DraftKey, string.Empty);
        if (!string.IsNullOrEmpty(saved))
            NoteEditor.Text = saved;
    }

    // Clear the draft when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- **`Window.Stopped`** fires when the app goes to the background — save here.
- **`Window.Resumed`** fires when it comes back — restore here.
- **`Preferences`** is ideal for small strings; for large text, use `SecureStorage` or write to `FileSystem.AppDataDirectory`.
- Call `ClearDraft()` when the user intentionally saves or discards the note so stale drafts don't reappear.
